        private static void forwBackwGenCheck(IFFT fft, Array<fcomplex> A, Array<fcomplex> Result, uint dim, float mult)
        {
            Array<fcomplex> B = fft.FFTForward1D(A, dim);
            if (sumall(abs(Result - B)) / A.Size.NumberOfElements / A.Size[dim] > Globals.epsf * mult)
                throw new Exception("invalid value");
            B = fft.FFTBackward1D(B, dim);
            if (sumall(abs(A - B)) / A.Size.NumberOfElements / A.Size[dim] > Globals.epsf * mult)
                throw new Exception("invalid value");
        }

        private static void forwBackwGenCheckND(IFFT fft, Array<fcomplex> A, Array<fcomplex> Result, uint d,float mult)
        {
            try
            {
                Array<fcomplex> B = fft.FFTForward(A, d);
                float errMult = A.Size.NumberOfElements;
                for (int i = 0; i < d; i++) errMult *= A.Size[i];
                if (sumall(abs(Result - B)) / errMult > Globals.epsf * mult)
                    throw new Exception("invalid value");
                B = fft.FFTBackward(B, d);
                if (sumall(abs(tofcomplex(A) - B)) / errMult > Globals.epsf * mult)
                    throw new Exception("invalid value");
            }
            catch (ArgumentException)
            {
                if (d < 0) return;
                throw new Exception("unexpected exception was thrown -> error!");
            }
        }

        private static void TEST_FFT1d1_1__ALONG1_2(IFFT fft)
        {
            Array<float> ResultR, ResultI;
            Array<fcomplex> A;
            Array<fcomplex> B, Result;
            ResultR = new float[] { 1.00000000000000000f };
            ResultI = new float[] { 1.00000000000000000f };
            A = ccomplex(ResultR, ResultI);
            A = A.Reshape(vector<long>(1, 1));
            ResultR = new float[] { 1.00000000000000000f };
            ResultI = new float[] { 1.00000000000000000f };
            Result = ccomplex(ResultR, ResultI);
            Result = Result.Reshape(vector<long>(1, 1));
            forwBackwGenCheck(fft, A, Result, 0, 1e2f);
            ResultR = new float[] { 1.00000000000000000f };
            ResultI = new float[] { 1.00000000000000000f };
            Result = ccomplex(ResultR, ResultI);
            Result = Result.Reshape(vector<long>(1, 1));
            forwBackwGenCheckND(fft, A, Result, 1, 1e2f);
            ResultR = new float[] { 1.00000000000000000f };
            ResultI = new float[] { 1.00000000000000000f };
            Result = ccomplex(ResultR, ResultI);
            Result = Result.Reshape(vector<long>(1, 1));
            forwBackwGenCheck(fft, A, Result, 1, 1e2f);
            ResultR = new float[] { 1.00000000000000000f };
            ResultI = new float[] { 1.00000000000000000f };
            Result = ccomplex(ResultR, ResultI);
            Result = Result.Reshape(vector<long>(1, 1));
            forwBackwGenCheckND(fft, A, Result, 2, 1e2f);
        }
